css:
.loader { --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); display: inline-flex; gap: .22em; font: 900 calc(var(--loader-size) * .28)/1 ui-sans-serif, system-ui, sans-serif; letter-spacing: .08em; perspective: 600px; }
.loader span { color: var(--accent); text-shadow: 0 0 16px color-mix(in srgb, var(--accent) 60%, transparent); animation: kinetic-letter calc(var(--speed) * 1.4) cubic-bezier(.6,-.3,.3,1.3) infinite; transform-origin: 50% 80%; }
.loader span:nth-child(2) { animation-delay: .12s; color: var(--accent-2); } .loader span:nth-child(3) { animation-delay: .24s; } .loader span:nth-child(4) { animation-delay: .36s; color: var(--accent-2); }
@keyframes kinetic-letter { 0%,100% { transform: translateY(0) rotateX(0) scale(1); opacity:.55; } 45% { transform: translateY(-18px) rotateX(55deg) scale(1.18); opacity:1; } }
